mapper.select:
select value, label from(

    select value ,
    label||'('||tableCount||')'as label
    from(
    select case when a.value is null then '中间表' else a.value end as value ,
    case when a.label is null then b.classifyCh else a.label end as label ,
    case when b.tableCount is null then 0 else b.tableCount end as tableCount
    from(
    select distinct CODEID as value ,CODETEXT as label from V_CLASSIFY_INFO where PARCODEID = #{sjzzflCodeId}
    ) a
    left join (
    select primaryorganizationch as classifyCh, count(*) as tableCount from classify_interface_all_date
    group by primaryorganizationch )
    b on a.label = b.classifyCh
    ) t1


    select value ,
    label||'('||tableCount||')'as label
    from(
    select case when a.value is null then '中间表' else a.value end as value ,
    case when a.label is null then b.classifyCh else a.label end as label ,
    case when b.tableCount is null then 0 else b.tableCount end as tableCount
    from(
    select distinct CODEID as value , CODETEXT as label from V_CLASSIFY_INFO where PARCODEID =
    'GACODE000404'
    ) a
    left join (
    select primarydatasourcech as classifyCh, count(*) as tableCount from classify_interface_all_date
    group by primarydatasourcech )
    b on a.label = b.classifyCh
    ) t1

) t2
order by value
